                <li className={currentStep === 2 ? 'is-active' : ''}>Select Movie</li>
                <li className={currentStep === 3 ? 'is-active' : ''}>Select Slots</li>
                <li className={currentStep === 4 ? 'is-active' : ''}>Confirm</li>
